import React from "react";

const AdminReports = () => {
  return (
    <div className="page">
      <div className="page-header-admin">
        <div>
          <div className="welcome-badge">📈 Analytics</div>
          <h1 className="admin-title">Reports & Insights</h1>
          <p className="admin-subtitle">View detailed analytics and generate comprehensive reports</p>
        </div>
        <button className="button">📥 Export Report</button>
      </div>

      <div className="card">
        <div className="empty-state">
          <div className="empty-state__icon">📊</div>
          <div className="empty-state__title">Reports Coming Soon</div>
          <div className="empty-state__desc">
            Advanced analytics and reporting features will be available here
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminReports;
